marmot_kernel_selection_t
marmot_metal_query_kernel(const marmot_op_signature_t *sig, const marmot_device_caps_t *caps) {
    if (sig == nullptr) {
        marmot_kernel_selection_t result = {
            .supported = false,
            .kernel_id = MARMOT_KERNEL_INVALID,
            .op_index = MARMOT_KERNEL_OP_INDEX_INVALID,
            .estimated_us = 0.0,
            .est_comm_us = 0.0,
            .est_workspace_mb = 0.0,
            .confidence = 0.0f,
            .fallback_reason = "Null signature",
            .shardable_axes = 0,
            .device_affinity = 0,
        };
        return result;
    }

    switch (sig->op_id) {
    case MARMOT_OP_RELU:
        return marmot_select_kernel_case(sig, caps, marmot_metal_relu_cases, MARMOT_ARRAY_LEN(marmot_metal_relu_cases));
    case MARMOT_OP_GELU:
        return marmot_select_kernel_case(sig, caps, marmot_metal_gelu_cases, MARMOT_ARRAY_LEN(marmot_metal_gelu_cases));
    case MARMOT_OP_GELU_TANH:
        return marmot_select_kernel_case(
            sig, caps, marmot_metal_gelu_tanh_cases, MARMOT_ARRAY_LEN(marmot_metal_gelu_tanh_cases)
        );
    case MARMOT_OP_SILU:
        return marmot_select_kernel_case(sig, caps, marmot_metal_silu_cases, MARMOT_ARRAY_LEN(marmot_metal_silu_cases));
    case MARMOT_OP_SIGMOID:
        return marmot_select_kernel_case(
            sig, caps, marmot_metal_sigmoid_cases, MARMOT_ARRAY_LEN(marmot_metal_sigmoid_cases)
        );
    case MARMOT_OP_TANH:
        return marmot_select_kernel_case(sig, caps, marmot_metal_tanh_cases, MARMOT_ARRAY_LEN(marmot_metal_tanh_cases));
    case MARMOT_OP_SQRT:
        return marmot_select_kernel_case(sig, caps, marmot_metal_sqrt_cases, MARMOT_ARRAY_LEN(marmot_metal_sqrt_cases));
    case MARMOT_OP_EXP:
        return marmot_select_kernel_case(sig, caps, marmot_metal_exp_cases, MARMOT_ARRAY_LEN(marmot_metal_exp_cases));
    case MARMOT_OP_LOG:
        return marmot_select_kernel_case(sig, caps, marmot_metal_log_cases, MARMOT_ARRAY_LEN(marmot_metal_log_cases));
    case MARMOT_OP_MISH:
        return marmot_select_kernel_case(sig, caps, marmot_metal_mish_cases, MARMOT_ARRAY_LEN(marmot_metal_mish_cases));
    case MARMOT_OP_ELU:
        return marmot_select_kernel_case(sig, caps, marmot_metal_elu_cases, MARMOT_ARRAY_LEN(marmot_metal_elu_cases));
    case MARMOT_OP_SELU:
        return marmot_select_kernel_case(sig, caps, marmot_metal_selu_cases, MARMOT_ARRAY_LEN(marmot_metal_selu_cases));
    case MARMOT_OP_LEAKY_RELU:
        return marmot_select_kernel_case(
            sig, caps, marmot_metal_leaky_relu_cases, MARMOT_ARRAY_LEN(marmot_metal_leaky_relu_cases)
        );
    case MARMOT_OP_PRELU:
        return marmot_select_kernel_case(
            sig, caps, marmot_metal_prelu_cases, MARMOT_ARRAY_LEN(marmot_metal_prelu_cases)
